// Game Instance Subsystem — survives level transitions
UCLASS()
class UQuestSubsystem : public UGameInstanceSubsystem {
    GENERATED_BODY()
public:
    virtual void Initialize(FSubsystemCollectionBase& Collection) override {
        // Load quest data
    }

    virtual void Deinitialize() override {
        // Cleanup
    }

    UFUNCTION(BlueprintCallable)
    void AcceptQuest(FName QuestID) { /* ... */ }

    UFUNCTION(BlueprintCallable)
    bool IsQuestComplete(FName QuestID) const { /* ... */ }
};

// Accessing from anywhere
UQuestSubsystem* Quests = GetGameInstance()->GetSubsystem<UQuestSubsystem>();
Quests->AcceptQuest(TEXT("MainQuest_01"));

